import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import NavigateBeforeIcon from '@mui/icons-material/NavigateBefore';

const HomePage = () => {
  const theme = useTheme();
  const [currentExample, setCurrentExample] = useState(0);
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Dynamic testimonial examples
  const examples = [
    {
      industry: "Life Coaching",
      original: "The coaching was good. I learned some things that helped me.",
      enhanced: "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.",
      client: "Michael T.",
      avatar: "M"
    },
    {
      industry: "Web Design",
      original: "They built a nice website for me. It works well.",
      enhanced: "The team at DesignPro delivered beyond my expectations. My new website has increased conversions by 43% in the first month alone. Their attention to detail and strategic approach to UX completely transformed my online presence.",
      client: "Jessica K.",
      avatar: "J"
    },
    {
      industry: "Fitness Training",
      original: "Good trainer. I lost some weight and feel better.",
      enhanced: "After 3 months with Alex, I've lost 28 pounds and completely transformed my relationship with fitness. His personalized approach addressed my specific challenges, and for the first time in my life, I actually look forward to my workouts!",
      client: "David R.",
      avatar: "D"
    }
  ];

  // Auto-rotate examples
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentExample((prev) => (prev + 1) % examples.length);
    }, 8000);
    return () => clearInterval(interval);
  }, [examples.length]);

  const handleNext = () => {
    setCurrentExample((prev) => (prev + 1) % examples.length);
  };

  const handlePrev = () => {
    setCurrentExample((prev) => (prev - 1 + examples.length) % examples.length);
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 8, md: 10 },
          pb: { xs: 10, md: 12 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography variant="h1" gutterBottom>
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  endIcon={<ArrowForwardIcon />}
                  sx={{ py: 1.5, px: 3 }}
                >
                  Enhance a Testimonial
                </Button>
                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ py: 1.5, px: 3 }}
                >
                  See How It Works
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="subtitle2" fontWeight={600}>
                  4.9/5
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ ml: 1 }}>
                  from 200+ users
                </Typography>
              </Box>
            </Grid>

            <Grid item xs={12} md={6}>
              <Box sx={{ position: 'relative' }}>
                <Card 
                  elevation={0} 
                  sx={{ 
                    borderRadius: 4,
                    border: '1px solid rgba(0, 0, 0, 0.08)',
                    overflow: 'visible',
                    position: 'relative',
                    zIndex: 2,
                    boxShadow: '0 10px 40px rgba(0, 0, 0, 0.1)',
                    transition: 'all 0.3s ease',
                  }}
                >
                  <Grid container>
                    <Grid item xs={5}>
                      <Box sx={{ p: 3, height: '100%', bgcolor: 'grey.50' }}>
                        <Typography variant="overline" color="text.secondary" fontWeight={600} sx={{ display: 'block', mb: 1 }}>
                          ORIGINAL TESTIMONIAL
                        </Typography>
                        <Typography variant="body1" sx={{ fontStyle: 'italic', color: 'text.secondary' }}>
                          "{examples[currentExample].original}"
                        </Typography>
                      </Box>
                    </Grid>

                    <Grid item xs={7}>
                      <Box sx={{ p: 3, height: '100%', bgcolor: 'primary.light', position: 'relative' }}>
                        <Box sx={{ position: 'absolute', top: 12, right: 12 }}>
                          <Chip
                            icon={<AutoAwesomeIcon />}
                            label="ENHANCED"
                            size="small"
                            sx={{ 
                              bgcolor: 'white', 
                              color: 'primary.main',
                              fontWeight: 600,
                              '& .MuiChip-icon': { color: 'primary.main' }
                            }}
                          />
                        </Box>

                        <Typography variant="body1" sx={{ fontWeight: 500, color: 'primary.dark', mt: 4 }}>
                          "{examples[currentExample].enhanced}"
                        </Typography>
                      </Box>
                    </Grid>
                  </Grid>

                  <Box sx={{ 
                    p: 2, 
                    borderTop: '1px solid rgba(0, 0, 0, 0.08)',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    bgcolor: 'white'
                  }}>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <Avatar sx={{ bgcolor: 'grey.200', color: 'text.primary', width: 36, height: 36, mr: 1.5 }}>
                        {examples[currentExample].avatar}
                      </Avatar>
                      <Box>
                        <Typography variant="subtitle2">
                          {examples[currentExample].client}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {examples[currentExample].industry}
                        </Typography>
                      </Box>
                    </Box>

                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <IconButton size="small" onClick={handlePrev} sx={{ mr: 1 }}>
                        <NavigateBeforeIcon />
                      </IconButton>

                      {examples.map((_, index) => (
                        <Box 
                          key={index}
                          onClick={() => setCurrentExample(index)}
                          sx={{ 
                            width: 8, 
                            height: 8, 
                            borderRadius: '50%', 
                            bgcolor: currentExample === index ? 'primary.main' : 'grey.300',
                            mx: 0.5,
                            cursor: 'pointer',
                            transition: 'all 0.2s ease'
                          }}
                        />
                      ))}

                      <IconButton size="small" onClick={handleNext} sx={{ ml: 1 }}>
                        <NavigateNextIcon />
                      </IconButton>
                    </Box>
                  </Box>
                </Card>
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: 'white' }}>
        <Container maxWidth="lg">
          <Typography variant="h2" align="center" gutterBottom>
            How It Works
          </Typography>
          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}>
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4} justifyContent="center">
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden',
              borderRadius: 4
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 4, 
                py: 1.5,
                bgcolor: 'white',
                color: 'primary.main',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)'
                }
              }}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
